#include<bits/stdc++.h>
using namespace std;

bool v[10001];
int num=1,n,m,k;
int main(){
	cin>>n>>m>>k;
	for(int i=0;i<m;i++){
		for(int j=1;j<=k;j++){
			if(v[i]) continue;
			num++;
			if(num>n+m){
				num=1;
			}
		}
		v[num]=1;
	}
	for(int i=1;i<=n+m;i++){
		if(!v[i]) cout<<i;
	}
	return 0 ;
}
